@MainActor
final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var account: UserAccount
    @Published private(set) var lastStatusMessage: String?

    private init() {
        self.account = UserAccountStore.shared.load() ?? UserAccount(userId: "user_123", promoCode: nil, discountPercent: 0, lastAppliedAt: nil)
        self.lastStatusMessage = nil
    }

    func handleIncomingUniversalLink(_ url: URL) -> Bool {
        guard let promo = PromoLinkParser.parse(url: url) else {
            lastStatusMessage = "Ignored URL: \(url.absoluteString)"
            return false
        }

        applyPromo(promo)
        return true
    }

    func applyPromo(_ promo: PromoPayload) {
        guard promo.discountPercent >= 0 && promo.discountPercent <= 100 else {
            lastStatusMessage = "Invalid discount \(promo.discountPercent)% for code \(promo.code)."
            return
        }

        account.promoCode = promo.code
        account.discountPercent = promo.discountPercent
        account.lastAppliedAt = Date()

        UserAccountStore.shared.save(account)

        lastStatusMessage = "Applied promo code \(promo.code) with \(promo.discountPercent)% discount."
    }

    func resetPromo() {
        account.promoCode = nil
        account.discountPercent = 0
        account.lastAppliedAt = nil
        UserAccountStore.shared.save(account)
        lastStatusMessage = "Promo reset."
    }
}

struct PromoPayload: Equatable {
    let code: String
    let discountPercent: Int
}

enum PromoLinkParser {
    static func parse(url: URL) -> PromoPayload? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }

        guard let host = components.host?.lowercased(),
              host == "myapp.com" else { return nil }

        let path = components.path.lowercased()
        guard path == "/promo" else { return nil }

        let items = components.queryItems ?? []
        let code = items.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountString = items.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard let codeUnwrapped = code, !codeUnwrapped.isEmpty,
              let discountStr = discountString, !discountStr.isEmpty,
              let discount = Int(discountStr) else { return nil }

        return PromoPayload(code: codeUnwrapped, discountPercent: discount)
    }
}

struct UserAccount: Codable, Equatable {
    var userId: String
    var promoCode: String?
    var discountPercent: Int
    var lastAppliedAt: Date?
}

final class UserAccountStore {
    static let shared = UserAccountStore()
    private let key = "UserAccountStore.account"

    private init() {}

    func load() -> UserAccount? {
        guard let data = UserDefaults.standard.data(forKey: key) else { return nil }
        return try? JSONDecoder().decode(UserAccount.self, from: data)
    }

    func save(_ account: UserAccount) {
        if let data = try? JSONEncoder().encode(account) {
            UserDefaults.standard.set(data, forKey: key)
        }
    }
}